export const DeleteSeoHistoryItemParams = zod.object({
  id: zod.coerce.number(),
});

/**
 * @summary Get Google keyword suggestions for a search query
 */
export const GetKeywordSuggestionsQueryParams = zod.object({
  query: zod.coerce.string(),
});

export const GetKeywordSuggestionsResponse = zod.object({
  query: zod.string(),
  suggestions: zod.array(zod.string()),
});

/**
 * @summary Get summary statistics for SEO optimizations
 */
export const GetSeoStatsResponse = zod.object({
  totalOptimizations: zod.number(),
  avgTitleScore: zod.number(),
  avgDescriptionScore: zod.number(),
  topKeywords: zod.array(zod.string()),
});
